{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select CT Volume",
      "simple": "Choose the CT volume for fracture planning from the dropdown list.",
      "detailed": "The CT scan of the fractured bone is the foundation for all subsequent segmentation and reduction planning. Select the appropriate volume from the list to begin."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create Reference Segmentation",
      "simple": "In the Segment Editor, add a new segmentation and name it 'Reference_Segmentation'.",
      "detailed": "This segmentation will hold the fixed reference bone fragment — the part of the bone that remains in its anatomical position. Creating a dedicated segmentation keeps your work organized."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add Reference Segment",
      "simple": "Click Add, rename the segment to 'Reference_Segment', and set its color to Sage Green.",
      "detailed": "This segment will contain the thresholded region corresponding to the reference (fixed) bone fragment. Using a distinct color helps you distinguish it from the moving fragment later."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open Threshold Effect",
      "simple": "Click the Threshold button in the Segment Editor.",
      "detailed": "Thresholding isolates bone tissue from soft tissue based on Hounsfield units. This step activates the threshold tool so you can define the intensity range that captures the reference fragment."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set Threshold Range",
      "simple": "Adjust the threshold slider to cover the bone density of the reference fragment.",
      "detailed": "Set the lower bound high enough to exclude soft tissue but low enough to include all of the reference bone fragment. The range you choose determines which voxels become part of the segmentation."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply Threshold",
      "simple": "Click Apply to generate the segmentation mask for the reference fragment.",
      "detailed": "This converts the threshold range into a visible segment in the segmentation node. Review the result to ensure the entire reference fragment is captured without holes or excess."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open Islands Effect",
      "simple": "Click the Islands button in the Segment Editor.",
      "detailed": "The Islands tool helps clean up the threshold result by removing disconnected components. This is essential for isolating just the reference bone fragment from surrounding bone fragments."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Keep Selected Island",
      "simple": "Choose 'Keep selected island' from the Islands options.",
      "detailed": "This mode lets you click on the fragment you want to keep — all other disconnected islands will be removed, leaving only the reference fragment."
    },
    {
      "step_id": "cb_step_9",
      "title": "Select Reference Fragment",
      "simple": "Click on the reference bone fragment in a slice view to keep it.",
      "detailed": "With the 'Keep selected island' effect active, clicking on the reference fragment in a slice view tells the tool to retain that connected component and discard the rest. Make sure to click on the correct fragment."
    },
    {
      "step_id": "cb_step_10",
      "title": "Create Moving Segmentation",
      "simple": "In the Segment Editor, add a new segmentation named 'Moving_Segmentation'.",
      "detailed": "This second segmentation will hold the moving (displaced) bone fragment that will be realigned. Keeping it separate from the reference allows independent manipulation."
    },
    {
      "step_id": "cb_step_11",
      "title": "Add Moving Segment",
      "simple": "Click Add, rename the segment to 'Moving_Segment', and set its color to Cyan.",
      "detailed": "This segment will contain the thresholded region of the moving fragment. The cyan color contrasts with the sage green reference for easy identification."
    },
    {
      "step_id": "cb_step_12",
      "title": "Open Threshold Effect",
      "simple": "Click the Threshold button again.",
      "detailed": "Activate the threshold tool for the moving segmentation to define the intensity range for the displaced fragment."
    },
    {
      "step_id": "cb_step_13",
      "title": "Set Threshold Range for Moving Fragment",
      "simple": "Adjust the threshold slider to cover the moving fragment (the default matches the previous range).",
      "detailed": "Use the same or a slightly adjusted threshold range to capture the moving bone fragment. The density of the displaced fragment may differ slightly due to rotation, so verify coverage."
    },
    {
      "step_id": "cb_step_14",
      "title": "Apply Threshold",
      "simple": "Click Apply to generate the segmentation mask for the moving fragment.",
      "detailed": "This creates the initial segmentation of the moving fragment. Ensure it captures the entire displaced fragment."
    },
    {
      "step_id": "cb_step_15",
      "title": "Open Islands Effect",
      "simple": "Click the Islands button.",
      "detailed": "Again, use the Islands tool to isolate the moving fragment from other disconnected components."
    },
    {
      "step_id": "cb_step_16",
      "title": "Select Keep Selected Island",
      "simple": "Choose 'Keep selected island'.",
      "detailed": "This prepares the tool for you to click on the moving fragment to retain only that island."
    },
    {
      "step_id": "cb_step_17",
      "title": "Select Moving Fragment",
      "simple": "Click on the moving bone fragment in a slice view to keep it.",
      "detailed": "With 'Keep selected island' active, click on the moving fragment to preserve it and remove any other islands, leaving just the displaced fragment."
    },
    {
      "step_id": "cb_step_18",
      "title": "Select Reference Segmentation",
      "simple": "From the dropdown, choose the 'Reference_Segmentation' node.",
      "detailed": "This identifies which segmentation contains the fixed reference fragment. The extension uses this as the stationary target for registration."
    },
    {
      "step_id": "cb_step_19",
      "title": "Reconstruct Reference in 3D",
      "simple": "Click the '3D Reconstruction (reference)' button to generate a 3D model of the reference fragment.",
      "detailed": "This creates a surface mesh from the reference segmentation, enabling 3D visualization and subsequent registration. A 3D model of the fixed fragment is essential for aligning the moving piece."
    },
    {
      "step_id": "cb_step_20",
      "title": "Select Moving Segmentation",
      "simple": "Choose the 'Moving_Segmentation' node from the dropdown.",
      "detailed": "This tells the extension which segmentation contains the displaced fragment to be realigned."
    },
    {
      "step_id": "cb_step_21",
      "title": "Reconstruct Moving in 3D",
      "simple": "Click the '3D Reconstruction (moving)' button to generate a 3D model of the moving fragment.",
      "detailed": "Creates a surface mesh for the moving fragment, which will be transformed during registration. Having both 3D models is prerequisite for fracture reduction planning."
    },
    {
      "step_id": "cb_step_22",
      "title": "Detect Fracture Surfaces",
      "simple": "Click the 'Detect fracture surfaces' button to automatically identify the fractured interfaces.",
      "detailed": "The algorithm analyzes the 3D models to find the broken surfaces that should mate together. This detection guides the registration to align the fragments anatomically."
    },
    {
      "step_id": "cb_step_23",
      "title": "Initialize Registration",
      "simple": "Click the 'Initialize registration' button to compute an initial alignment.",
      "detailed": "This performs an initial alignment of the moving fragment to the reference based on the detected fracture surfaces. It provides a starting point for fine-tuning."
    },
    {
      "step_id": "cb_step_24",
      "title": "Adjust View for Alignment",
      "simple": "Rotate, zoom, and pan the 3D view to inspect the initial alignment.",
      "detailed": "Getting a clear view of the fracture interface from multiple angles helps you assess the alignment quality. Adjust the 3D view to see both fragments together — you are only adjusting the camera, not moving anything yet."
    },
    {
      "step_id": "cb_step_25",
      "title": "Reduce Fracture",
      "simple": "Click the 'Reduction planning' button to compute the optimal reduction plan.",
      "detailed": "This uses the initialized registration and fracture surface detection to calculate a final repositioning transform. The result brings the moving fragment into near-anatomical alignment."
    },
    {
      "step_id": "cb_step_26",
      "title": "Check Alignment Result",
      "simple": "If the alignment looks good, stop here. If further refinements are needed, check the manual adjustment box.",
      "detailed": "Review the reduced position. If the fragments are anatomically aligned, the planning is complete. If not, you can manually adjust the moving fragment with additional controls."
    },
    {
      "step_id": "cb_step_27",
      "title": "Refine View for Manual Adjustment",
      "simple": "Rotate, zoom, and pan the 3D view to thoroughly inspect the alignment from all angles.",
      "detailed": "Before making any manual adjustments, ensure you have a clear vantage of the fracture gap and any rotation mismatch. Adjust your view to see small gaps or overlaps, allowing precise fine-tuning in the next step."
    },
    {
      "step_id": "cb_step_28",
      "title": "Finalize Alignment",
      "simple": "Click the 'Harden transform into moving fragment' button to permanently apply the transform to the moving fragment.",
      "detailed": "This makes the alignment permanent in the volume data. After hardening, the moving fragment's segmentation and model are updated to their final position, completing the reduction planning."
    }
  ]
}
